package arch.day60;

public class Day60Advanced {
    public static void main(String[] args) {
        int attempts = 0;
        int max = 5;
        boolean ok = false;
        while (!ok && attempts < max) {
            attempts++;
            ok = attempts >= 3;
        }
        System.out.println("attempts=" + attempts + " ok=" + ok);
    }
}

